import React, { useEffect, useState } from "react";
import axios from "axios";

const Bill = () => {
  const [bills, setBills] = useState([]);
  const [form, setForm] = useState({
    MaHD: "",
    PhongSo: "",
    NgayNhan: "",
    NgayTra: "",
    PhuongThucTT: "",
  });
  const [editMode, setEditMode] = useState(false);

  // lấy danh sách hóa đơn
  const fetchBills = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/bill/getall");
      setBills(res.data);
    } catch (err) {
      console.error("❌ Lỗi lấy hóa đơn:", err);
    }
  };

  useEffect(() => {
    fetchBills();
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // thêm hóa đơn
  const handleAdd = async () => {
    try {
      await axios.post("http://localhost:5000/api/bill/addbill", form);
      fetchBills();
      setForm({
        MaHD: "",
        PhongSo: "",
        NgayNhan: "",
        NgayTra: "",
        PhuongThucTT: "",
      });
    } catch (err) {
      console.error("❌ Lỗi thêm hóa đơn:", err);
    }
  };

  // cập nhật hóa đơn
  const handleUpdate = async () => {
    try {
      await axios.put("http://localhost:5000/api/bill/updatebill", form);
      fetchBills();
      setForm({
        MaHD: "",
        PhongSo: "",
        NgayNhan: "",
        NgayTra: "",
        PhuongThucTT: "",
      });
      setEditMode(false);
    } catch (err) {
      console.error("❌ Lỗi cập nhật hóa đơn:", err);
    }
  };

  // sửa
  const handleEdit = (bill) => {
    setForm({
      MaHD: bill.MaHD,
      PhongSo: bill.PhongSo,
      NgayNhan: bill.NgayNhan ? bill.NgayNhan.substring(0, 10) : "",
      NgayTra: bill.NgayTra ? bill.NgayTra.substring(0, 10) : "",
      PhuongThucTT: bill.PhuongThucTT,
    });
    setEditMode(true);
  };

  // xóa
  const handleDelete = async (MaHD) => {
    try {
      await axios.delete(`http://localhost:5000/api/bill/deletebill/${MaHD}`);
      fetchBills();
    } catch (err) {
      console.error("❌ Lỗi xóa hóa đơn:", err);
    }
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Quản lý hóa đơn</h1>

      {/* Form thêm/sửa */}
      <div className="mb-6 border p-4 rounded-lg">
        <h2 className="text-lg font-semibold mb-3">
          {editMode ? "Sửa hóa đơn" : "Thêm hóa đơn"}
        </h2>
        <div className="flex flex-col gap-3">
          <input
            type="text"
            name="MaHD"
            placeholder="Mã hóa đơn"
            value={form.MaHD}
            onChange={handleChange}
            className="border p-2 rounded"
            disabled={editMode}
          />
          <input
            type="text"
            name="PhongSo"
            placeholder="Phòng số"
            value={form.PhongSo}
            onChange={handleChange}
            className="border p-2 rounded"
          />
          <input
            type="date"
            name="NgayNhan"
            value={form.NgayNhan}
            onChange={handleChange}
            className="border p-2 rounded"
          />
          <input
            type="date"
            name="NgayTra"
            value={form.NgayTra}
            onChange={handleChange}
            className="border p-2 rounded"
          />
          <select
            name="PhuongThucTT"
            value={form.PhuongThucTT}
            onChange={handleChange}
            className="border p-2 rounded"
          >
            <option value="">-- Chọn phương thức thanh toán --</option>
            <option value="TienMat">Tiền mặt</option>
            <option value="ChuyenKhoan">Chuyển khoản</option>
            <option value="The">Thẻ</option>
          </select>

          {editMode ? (
            <button
              onClick={handleUpdate}
              className="bg-blue-500 text-white px-4 py-2 rounded"
            >
              Cập nhật
            </button>
          ) : (
            <button
              onClick={handleAdd}
              className="bg-green-500 text-white px-4 py-2 rounded"
            >
              Thêm
            </button>
          )}
        </div>
      </div>

      {/* Bảng hóa đơn */}
      <table className="w-full border-collapse border">
        <thead>
          <tr className="bg-gray-200">
            <th className="border p-2">Mã HD</th>
            <th className="border p-2">Phòng số</th>
            <th className="border p-2">Ngày nhận</th>
            <th className="border p-2">Ngày trả</th>
            <th className="border p-2">Phương thức TT</th>
            <th className="border p-2">Tổng DV</th>
            <th className="border p-2">Tổng tiền</th>
            <th className="border p-2">Hành động</th>
          </tr>
        </thead>
        <tbody>
          {bills.map((bill) => (
            <tr key={bill.MaHD}>
              <td className="border p-2">{bill.MaHD}</td>
              <td className="border p-2">{bill.PhongSo}</td>
              <td className="border p-2">
                {bill.NgayNhan ? bill.NgayNhan.substring(0, 10) : ""}
              </td>
              <td className="border p-2">
                {bill.NgayTra ? bill.NgayTra.substring(0, 10) : ""}
              </td>
              <td className="border p-2">{bill.PhuongThucTT}</td>
              <td className="border p-2">{bill.TongDV}</td>
              <td className="border p-2">{bill.TongTien}</td>
              <td className="border p-2 flex gap-2">
                <button
                  onClick={() => handleEdit(bill)}
                  className="bg-yellow-500 text-white px-3 py-1 rounded"
                >
                  Sửa
                </button>
                <button
                  onClick={() => handleDelete(bill.MaHD)}
                  className="bg-red-500 text-white px-3 py-1 rounded"
                >
                  Xóa
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Bill;
